import React, { useState } from 'react';

export default function TextFrom(props) {
  const handleUpClick = () => {
    // console.log("Uppercase was clicked");
    let newText = text.toUpperCase();
    setText(newText)
}
  const handleLowClick = () => {
    // console.log("Uppercase was clicked");
    let newText = text.toLowerCase();
    setText(newText)
}
  const handleClear = () => {
    // console.log("Uppercase was clicked");
    let newText =" ";
    setText(newText)
}
const handleOnChange = (event) => {
  // console.log("On change");
  setText(event.target.value);
}
    const [text, setText] = useState("Enter Your Text");
  return (
    <>
      <form>
        <div className={`container my-3 text-${props.mode==='dark'?'dark':'light'}`}>
            <h1>{props.heading}</h1>
          <div className="form-group">
          <textarea className="form-control" value={text}  onChange={handleOnChange}  id='mybox' rows="4"></textarea>
          </div>
        <button type="button" className="btn btn-primary mx-2" onClick={handleUpClick}>ConvertToUpperCase</button>
        <button type="button" className="btn btn-primary mx-2" onClick={handleLowClick}>ConvertToLowerCase</button>
        <button type="button" className="btn btn-primary mx-2" onClick={handleClear}>Clear</button>
        </div>
        <div className="container my-3">
          <h2>Your Text Summary </h2>
         <b><p>Paragraph is:{text.split("\n").length} Words is:{text.split(" ").length} and charachter is:{text.length}</p></b> 
          <b><p>Reading Words per Minute:{0.008*text.split(" ").length} </p></b>
          <h2>Priview  </h2>
          <p>{text}</p>
        </div>
      </form>
    </>
  );
}
